function o(t){const r=typeof t=="string"?parseFloat(t):t;return`${new Intl.NumberFormat("vi-VN").format(r||0)} đ`}function e(t){if(t==null)return"0";const r=typeof t=="string"?parseFloat(t):t;return new Intl.NumberFormat("vi-VN").format(r||0)}function f(t){if(t==null)return"0";const n=(typeof t=="string"?parseFloat(t):t)||0;return Math.abs(n)>=1e9?`${parseFloat((n/1e9).toFixed(1))} tỷ`:Math.abs(n)>=1e6?`${Math.round(n/1e6)} tr`:new Intl.NumberFormat("vi-VN").format(Math.round(n))}function s(t){if(t==null)return"0%";const r=typeof t=="string"?parseFloat(t):t;return`${parseFloat(r.toFixed(2))}%`}export{e as a,s as b,f as c,o as f};
